func mergeReviewDisplayName(soldier viewmodel.PersonRecord) string {
	name := strings.TrimSpace(soldier.GetFullName())
	if name == "" {
		return soldier.DisplayID
	}
	return name
}

func boolFlag(value bool) string {
	if value {
		return "1"
	}
	return "0"
}

