func updateStatusCardClasses(kind string) string {
	switch strings.ToLower(strings.TrimSpace(kind)) {
	case "success":
		return "border-[rgba(91,143,101,0.25)] bg-[rgba(242,252,244,0.95)] text-[#29522d]"
	case "failed", "error":
		return "border-[rgba(176,70,70,0.25)] bg-[rgba(255,245,245,0.95)] text-[#7a2d2d]"
	default:
		return "border-[rgba(141,116,64,0.35)] bg-white/80 text-slate-700"
	}
}

func updateStatusHeading(kind string) string {
	switch strings.ToLower(strings.TrimSpace(kind)) {
	case "success":
		return "Last update applied successfully"
	case "failed", "error":
		return "Last update attempt failed"
	default:
		return "Last update result"
	}
}

