func previewUpdatedByline(s viewmodel.PersonRecord) string {
	if strings.TrimSpace(s.LastEditedBy) != "" && strings.TrimSpace(s.LastEditedAt) != "" {
		return s.LastEditedBy + " • " + formatAuditTimestamp(s.LastEditedAt)
	}
	if strings.TrimSpace(s.LastEditedBy) != "" {
		return s.LastEditedBy
	}
	return formatAuditTimestamp(s.LastEditedAt)
}

func previewConfederateHomeLabel(s viewmodel.PersonRecord) string {
	status := normalizedConfederateHomeStatus(s.ConfederateHomeStatus)
	if strings.TrimSpace(s.ConfederateHomeName) != "" && status != confederatehomestatus.NotApplicable {
		return status + " • " + s.ConfederateHomeName
	}
	if strings.TrimSpace(s.ConfederateHomeName) != "" {
		return s.ConfederateHomeName
	}
	return status
}

func normalizedConfederateHomeStatus(value string) string {
	return confederatehomestatus.Normalize(value)
}

func previewCompareLabel(s viewmodel.PersonRecord) string {
	if s.EntryType == "linked_person" {
		return "Compare Person Records"
	}
	return "Compare Family Person Records"
}

func entryFormBackHref(s viewmodel.PersonRecord, isEdit bool) string {
	if isEdit && s.ID > 0 {
		return fmt.Sprintf("/soldiers/%d", s.ID)
	}
	return "/soldiers"
}

func previewText(value string, limit int) string {
	trimmed := strings.TrimSpace(strings.ReplaceAll(value, "\r\n", "\n"))
	if limit <= 0 || len(trimmed) <= limit {
		return trimmed
	}
	candidate := strings.TrimSpace(trimmed[:limit])
	lastBreak := strings.LastIndexAny(candidate, " \n\t")
	if lastBreak > 40 {
		candidate = strings.TrimSpace(candidate[:lastBreak])
	}
	return candidate + "..."
}

